{# Work Order RA Bill — V1 print format. #}

<style>
  .rab-print, .rab-print * { box-sizing: border-box; }
  .rab-print {
    font-family: "Helvetica Neue", "Segoe UI", "Inter", Arial, sans-serif;
    color: #111;
    font-size: 9.5pt;
    line-height: 1.5;
    font-variant-numeric: tabular-nums;
    -webkit-font-feature-settings: "tnum";
    font-feature-settings: "tnum";
  }
  .rab-print p { margin: 0 0 6px; }
  .rab-print .negative { color: #a91414; }

  .rab-print .display-title {
    font-family: "Georgia", "Times New Roman", "Cambria", serif;
    font-size: 26pt; font-weight: 700; letter-spacing: 4pt;
    text-align: center; color: #1a2942; margin: 0; line-height: 1.1;
  }
  .rab-print .display-sub {
    font-size: 9pt; letter-spacing: 3pt; text-transform: uppercase;
    text-align: center; color: #666; margin: 4px 0 0;
  }
  .rab-print .section-label {
    font-size: 8.5pt; letter-spacing: 2.5pt; text-transform: uppercase;
    color: #1a2942; font-weight: 600;
    margin: 22px 0 8px; padding-bottom: 4px;
    border-bottom: 1px solid #1a2942;
  }
  .rab-print .muted { color: #777; font-size: 8.5pt; }

  /* Cover */
  .rab-print .cover-block {
    border-top: 3px solid #1a2942; border-bottom: 1px solid #1a2942;
    padding: 18px 0 16px; margin-bottom: 22px;
  }
  .rab-print .cover-meta {
    margin-top: 14px; display: table; width: 100%; border-collapse: collapse;
  }
  .rab-print .cover-meta > div {
    display: table-cell; padding: 0 6px; vertical-align: top;
    width: 25%; text-align: center;
  }
  .rab-print .meta-label {
    font-size: 7.5pt; letter-spacing: 1.5pt; text-transform: uppercase;
    color: #888; margin-bottom: 2px;
  }
  .rab-print .meta-value {
    font-size: 11pt; font-weight: 600; color: #1a2942;
    letter-spacing: 0.3pt;
  }
  .rab-print .status-pill {
    display: inline-block; padding: 1px 8px;
    font-size: 7.5pt; letter-spacing: 1.5pt; text-transform: uppercase;
    font-weight: 600; border: 1px solid #1a2942; color: #1a2942;
    border-radius: 2px;
  }
  .rab-print .status-pill.cancelled { color: #a91414; border-color: #a91414; }
  .rab-print .status-pill.draft     { color: #b75c00; border-color: #b75c00; }

  /* Parties */
  .rab-print .parties { width: 100%; border-collapse: collapse; margin: 0 0 8px; }
  .rab-print .parties td { width: 50%; padding: 12px 16px 12px 0; vertical-align: top; }
  .rab-print .parties td + td { padding-left: 16px; border-left: 1px solid #ddd; }
  .rab-print .party-role {
    font-size: 7.5pt; letter-spacing: 2pt; text-transform: uppercase;
    color: #888; margin-bottom: 3px;
  }
  .rab-print .party-name { font-size: 11pt; font-weight: 700; color: #111; line-height: 1.3; }

  /* Summary table */
  .rab-print .summary-table { width: 100%; border-collapse: collapse; margin: 6px 0 8px; }
  .rab-print .summary-table th, .rab-print .summary-table td {
    padding: 8px 10px; border-bottom: 1px solid #e6e6e6;
    text-align: left; font-size: 10pt;
  }
  .rab-print .summary-table th {
    font-size: 7.5pt; letter-spacing: 1.5pt; text-transform: uppercase;
    color: #888; font-weight: 600; border-bottom: 1.5px solid #1a2942;
    padding-top: 6px; padding-bottom: 6px;
  }
  .rab-print .summary-table td.amt, .rab-print .summary-table th.amt {
    text-align: right; white-space: nowrap;
  }
  .rab-print .summary-table .net-row td {
    border-top: 1.5px solid #1a2942; border-bottom: none;
    font-weight: 700; color: #1a2942; font-size: 11pt; padding-top: 10px;
  }

  /* Deductions table */
  .rab-print .ded-table { width: 100%; border-collapse: collapse; margin: 4px 0 6px; font-size: 9pt; }
  .rab-print .ded-table th, .rab-print .ded-table td {
    padding: 6px 8px; border-bottom: 1px solid #e6e6e6; vertical-align: top;
  }
  .rab-print .ded-table thead th {
    background: #f5f5f3; text-align: left;
    font-size: 7.5pt; letter-spacing: 1.2pt; text-transform: uppercase;
    color: #555; font-weight: 600; border-bottom: 1px solid #999;
  }
  .rab-print .ded-table td.amt, .rab-print .ded-table th.amt {
    text-align: right; white-space: nowrap;
  }
  .rab-print .ded-table tfoot td {
    background: #fafafa; font-weight: 700; color: #1a2942;
    font-size: 9.5pt; padding: 7px 8px; border-top: 1px solid #999;
    border-bottom: none;
  }
  .rab-print .ded-table .badge {
    display: inline-block; padding: 1px 5px; font-size: 7pt;
    letter-spacing: 0.4pt; font-weight: 600; border-radius: 2px;
    background: #eef3f7; color: #1a2942;
  }

  /* Amount-in-words callout */
  .rab-print .amount-in-words {
    background: #faf8f3; border-left: 3px solid #c9a25a;
    padding: 10px 14px; margin: 10px 0 6px;
    font-style: italic; color: #4d3a14; font-size: 9.5pt;
  }

  /* BOQ detail / per-scope items table */
  .rab-print .items-table {
    width: 100%; border-collapse: collapse; margin: 0 0 12px;
    font-size: 9pt;
  }
  .rab-print .items-table th, .rab-print .items-table td {
    padding: 5px 5px; border-bottom: 1px solid #e6e6e6; vertical-align: top;
  }
  .rab-print .items-table thead th {
    background: #1a2942; color: #fff; text-align: left;
    font-size: 7.5pt; letter-spacing: 0.6pt; text-transform: uppercase;
    font-weight: 600; padding: 6px 5px;
  }
  .rab-print .items-table th.amt, .rab-print .items-table td.amt {
    text-align: right; white-space: nowrap;
  }
  .rab-print .items-table tfoot td {
    background: #1a2942; color: #fff; font-weight: 700;
    font-size: 10pt; padding: 8px 5px; letter-spacing: 0.4pt;
    border-bottom: none;
  }
  .rab-print .scope-tag {
    display: inline-block; padding: 1px 5px; font-size: 7pt;
    letter-spacing: 0.4pt; font-weight: 600; border-radius: 2px;
    border: 1px solid #ccc; color: #555; background: #fafafa;
  }
  .rab-print .scope-tag.orig { color: #1a2942; border-color: #1a2942; background: #eaf2fb; }
  .rab-print .scope-tag.var  { color: #8b6c2c; border-color: #c9a25a; background: #faf8f3; }

  /* Signatures */
  .rab-print .signature-block { margin-top: 28px; page-break-inside: avoid; }
  .rab-print .sig-grid {
    width: 100%; border-collapse: separate;
    border-spacing: 24px 0; margin-top: 6px;
  }
  .rab-print .sig-grid td { width: 33.33%; padding: 0; vertical-align: top; }
  .rab-print .sig-role {
    font-size: 7.5pt; letter-spacing: 2pt; text-transform: uppercase;
    color: #888; margin-bottom: 4px;
  }
  .rab-print .sig-name {
    font-size: 9.5pt; font-weight: 700; color: #111;
    line-height: 1.35; min-height: 42px; margin-bottom: 30px;
    display: flex; align-items: flex-start;
  }
  .rab-print .sig-line { border-top: 1px solid #333; margin-bottom: 4px; }
  .rab-print .sig-caption {
    font-size: 8.5pt; color: #555; font-weight: 600; margin-bottom: 6px;
  }
  .rab-print .sig-detail {
    font-size: 8.5pt; color: #777; line-height: 1.7;
  }
  .rab-print .sig-detail span {
    display: inline-block; min-width: 50pt;
    border-bottom: 1px dotted #999; padding: 0 4px;
  }

  /* Annexure cover (page 2) */
  .rab-print .annexure-cover { text-align: center; padding: 30pt 0 22pt; }
  .rab-print .annexure-overline {
    font-size: 8pt; letter-spacing: 4pt; text-transform: uppercase;
    color: #888; margin-bottom: 4px;
  }
  .rab-print .annexure-title {
    font-family: "Georgia", "Times New Roman", "Cambria", serif;
    font-size: 22pt; font-weight: 700; color: #1a2942;
    letter-spacing: 2pt; margin: 0;
  }
  .rab-print .annexure-rule {
    width: 80pt; border-top: 2px solid #c9a25a;
    margin: 12px auto 14px;
  }
  .rab-print .annexure-ref {
    font-size: 9pt; color: #555; margin: 0; letter-spacing: 0.3pt;
  }

  .rab-print .doc-footnote {
    margin-top: 22px; padding-top: 8px; border-top: 1px solid #e8e8e8;
    font-size: 8pt; color: #888; text-align: center; line-height: 1.4;
  }
  .rab-print .page-break { page-break-after: always; break-after: page; }
  .rab-print .no-break  { page-break-inside: avoid; }
  .rab-print table     { page-break-inside: auto; }
  .rab-print thead     { display: table-header-group; }
  .rab-print tfoot     { display: table-footer-group; }
  .rab-print tr        { page-break-inside: avoid; }
</style>

{# Helpers — match the WO contract / variation print conventions #}
{%- set company_currency = frappe.db.get_value("Company", doc.company, "default_currency") or "INR" -%}
{%- macro money(amt) -%}{% if amt is none %}—{% else %}{{ frappe.utils.fmt_money(amt or 0, currency=company_currency) }}{% endif %}{%- endmacro -%}
{%- macro signed_money(v) -%}{% if v is none %}—{% elif (v|float) < 0 %}<span class="negative">{{ frappe.utils.fmt_money(v|float, currency=company_currency) }}</span>{% else %}{{ frappe.utils.fmt_money(v|float, currency=company_currency) }}{% endif %}{%- endmacro -%}
{%- macro show_date(d) -%}{%- if d -%}{{ frappe.utils.formatdate(d, "dd MMM yyyy") }}{%- else -%}—{%- endif -%}{%- endmacro -%}
{%- macro qty(v) -%}{% if v is none %}—{% else %}{{ "{:,.3f}".format(v|float) }}{% endif %}{%- endmacro -%}

{# Parent Work Order context #}
{%- set wo = frappe.get_doc("Work Order Contract", doc.civil_work_order) -%}

<div class="rab-print">

{# ================================================== #}
{# COVER BLOCK                                         #}
{# ================================================== #}

<div class="cover-block">
  <h1 class="display-title">RUNNING ACCOUNT BILL</h1>
  <p class="display-sub">Bill No. {{ doc.bill_number or 0 }} &nbsp;·&nbsp; against Work Order {{ doc.civil_work_order }}</p>
  <div class="cover-meta">
    <div>
      <div class="meta-label">Bill No.</div>
      <div class="meta-value">{{ doc.name }}</div>
    </div>
    <div>
      <div class="meta-label">Bill Date</div>
      <div class="meta-value">{{ show_date(doc.bill_date) }}</div>
    </div>
    <div>
      <div class="meta-label">Billing Period</div>
      <div class="meta-value" style="font-size: 9.5pt;">
        {%- if doc.period_from or doc.period_to -%}
          {{ show_date(doc.period_from) }} to {{ show_date(doc.period_to) }}
        {%- else -%}—{%- endif -%}
      </div>
    </div>
    <div>
      <div class="meta-label">Status</div>
      <div class="meta-value">
        {%- if doc.docstatus == 0 -%}<span class="status-pill draft">Draft</span>
        {%- elif doc.docstatus == 1 -%}<span class="status-pill">{{ doc.billing_status or "Submitted" }}</span>
        {%- elif doc.docstatus == 2 -%}<span class="status-pill cancelled">Cancelled</span>
        {%- endif -%}
      </div>
    </div>
  </div>
</div>

{# ================================================== #}
{# PARTIES                                             #}
{# ================================================== #}

<table class="parties">
  <tr>
    <td>
      <div class="party-role">Employer</div>
      <div class="party-name">{{ doc.company }}</div>
    </td>
    <td>
      <div class="party-role">Contractor</div>
      <div class="party-name">{{ wo.supplier_name or wo.supplier }}</div>
    </td>
  </tr>
</table>

<div class="muted" style="margin: 6px 0 0;">
  <strong>Work Order:</strong> {{ doc.civil_work_order }}{% if wo.work_title %} — {{ wo.work_title }}{% endif %}
</div>

{# ================================================== #}
{# BILL SUMMARY                                        #}
{# ================================================== #}

<div class="section-label">Bill Summary</div>
<table class="summary-table">
  <tbody>
    <tr>
      <td>Gross Value of Work Done This Bill (excl. tax)</td>
      <td class="amt">{{ money(doc.gross_this_bill) }}</td>
    </tr>
    {% if (doc.gross_this_bill_with_tax or 0) != (doc.gross_this_bill or 0) %}
    <tr>
      <td>Gross Value (incl. tax)</td>
      <td class="amt">{{ money(doc.gross_this_bill_with_tax) }}</td>
    </tr>
    {% endif %}
    <tr>
      <td>Less: Total Deductions</td>
      <td class="amt">−{{ money(doc.total_deductions) }}</td>
    </tr>
    {% if (doc.total_additions or 0) > 0 %}
    <tr>
      <td>Plus: Total Additions</td>
      <td class="amt">+{{ money(doc.total_additions) }}</td>
    </tr>
    {% endif %}
  </tbody>
  <tfoot>
    <tr class="net-row">
      <td>Net Payable</td>
      <td class="amt">{{ money(doc.net_payable) }}</td>
    </tr>
  </tfoot>
</table>

<div class="amount-in-words">
  Net Payable (in words): {{ frappe.utils.money_in_words(doc.net_payable or 0, company_currency) }}
</div>

{# ================================================== #}
{# DEDUCTIONS / ADDITIONS BREAKDOWN                    #}
{# ================================================== #}

{% if doc.deductions %}
<div class="section-label">Deductions &amp; Additions Breakdown</div>
<table class="ded-table">
  <thead>
    <tr>
      <th style="width: 22%;">Nature</th>
      <th>Description</th>
      <th style="width: 12%;">GL Account</th>
      <th class="amt" style="width: 16%;">Amount</th>
    </tr>
  </thead>
  <tbody>
    {%- set ns = namespace(ded=0, add=0) -%}
    {% for d in doc.deductions %}
      {%- set is_addition = d.nature in ("Price Escalation", "Other Addition") -%}
      {%- if is_addition -%}{%- set ns.add = ns.add + (d.amount or 0) -%}{%- else -%}{%- set ns.ded = ns.ded + (d.amount or 0) -%}{%- endif -%}
      <tr>
        <td>
          <span class="badge">{{ d.nature }}</span>
          {% if d.is_auto_suggested %}<br><span class="muted" style="font-size: 7pt;">auto</span>{% endif %}
        </td>
        <td>{{ d.description or "" }}</td>
        <td class="muted" style="font-size: 8pt;">{{ d.gl_account or "—" }}</td>
        <td class="amt">{% if is_addition %}+{% else %}−{% endif %}{{ money(d.amount) }}</td>
      </tr>
    {% endfor %}
  </tbody>
  <tfoot>
    <tr>
      <td colspan="3">Net effect on Gross (Additions − Deductions)</td>
      <td class="amt">{{ signed_money(ns.add - ns.ded) }}</td>
    </tr>
  </tfoot>
</table>
{% endif %}

{# ================================================== #}
{# SIGNATURES                                          #}
{# ================================================== #}

<div class="signature-block">
  <div class="section-label" style="margin-top: 0;">Certified &amp; Approved</div>
  <p class="muted" style="margin-top: -4px;">The work covered by this Running Account Bill has been measured, certified, and approved as detailed in Annexure 1.</p>
  <table class="sig-grid">
    <tr>
      <td>
        <div class="sig-role">Measured By</div>
        <div class="sig-name">Site Engineer</div>
        <div class="sig-line"></div>
        <div class="sig-caption">Signature</div>
        <div class="sig-detail">
          Name <span></span><br>
          Date <span></span>
        </div>
      </td>
      <td>
        <div class="sig-role">Checked By</div>
        <div class="sig-name">Project / Resident Engineer</div>
        <div class="sig-line"></div>
        <div class="sig-caption">Signature</div>
        <div class="sig-detail">
          Name <span></span><br>
          Date <span></span>
        </div>
      </td>
      <td>
        <div class="sig-role">Approved For Payment</div>
        <div class="sig-name">{{ doc.company }}</div>
        <div class="sig-line"></div>
        <div class="sig-caption">Authorized Signatory</div>
        <div class="sig-detail">
          Name <span></span><br>
          Date <span></span>
        </div>
      </td>
    </tr>
  </table>

  <div style="margin-top: 22px;">
    <div class="sig-role">Received Payment / Contractor</div>
    <div style="margin-top: 6px;">
      <div class="sig-name" style="min-height: 36px;">{{ wo.supplier_name or wo.supplier }}</div>
      <div style="width: 60%;">
        <div class="sig-line"></div>
        <div class="sig-caption">Signature &amp; Date</div>
      </div>
    </div>
  </div>
</div>

<div class="doc-footnote">
  Detailed Bill of Items (per-scope split) — see <strong>Annexure 1</strong>. It forms an integral part of this Running Account Bill.<br>
  {{ doc.name }} &nbsp;·&nbsp; against Work Order {{ doc.civil_work_order }} &nbsp;·&nbsp; Generated from {{ doc.company }}'s contract management system.
</div>

<div class="page-break"></div>

{# ================================================== #}
{# ANNEXURE 1 — DETAILED BILL ITEMS (per-scope split)  #}
{# ================================================== #}

<div class="annexure-cover">
  <div class="annexure-overline">Annexure 1</div>
  <h1 class="annexure-title">Detailed Bill Items</h1>
  <div class="annexure-rule"></div>
  <p class="annexure-ref">to Running Account Bill <strong>{{ doc.name }}</strong> dated {{ show_date(doc.bill_date) }}</p>
</div>

<p class="muted" style="margin-bottom: 10px;">
  Per-scope breakdown produced by the variation-aware allocator: when the
  parent Work Order has approved variations, a single cumulative entry per
  item is auto-split left-to-right across the original BOQ and additive
  variation scopes. Each row below is tagged to its <strong>scope</strong>
  (Original or Variation N).
</p>

{% if doc.items %}
<table class="items-table">
  <colgroup>
    <col style="width: 5%;">
    <col style="width: 5%;">
    <col style="width: 10%;">
    <col>
    <col style="width: 6%;">
    <col style="width: 8%;">
    <col style="width: 9%;">
    <col style="width: 9%;">
    <col style="width: 7%;">
    <col style="width: 6%;">
    <col style="width: 11%;">
  </colgroup>
  <thead>
    <tr>
      <th>S.No.</th>
      <th>Item</th>
      <th>Scope</th>
      <th>Description</th>
      <th>UOM</th>
      <th class="amt">Prev. Cum</th>
      <th class="amt">Cum. Now</th>
      <th class="amt">This Bill Qty</th>
      <th class="amt">Rate</th>
      <th class="amt">Tax %</th>
      <th class="amt">This Bill Amt</th>
    </tr>
  </thead>
  <tbody>
    {% for r in doc.items %}
    {%- set tag_class = "orig" if r.scope_source == "Original" else "var" -%}
    <tr>
      <td>{{ loop.index }}</td>
      <td>{{ r.item_no or "" }}</td>
      <td><span class="scope-tag {{ tag_class }}">{{ r.scope_source or "" }}</span></td>
      <td>{{ r.description or "" }}</td>
      <td>{{ r.uom or "" }}</td>
      <td class="amt">{{ qty(r.previous_cumulative_qty) }}</td>
      <td class="amt">{{ qty(r.cumulative_qty) }}</td>
      <td class="amt">{{ qty(r.this_bill_qty) }}</td>
      <td class="amt">{{ money(r.rate) }}</td>
      <td class="amt">{{ "%.2f"|format(r.tax_pct|float if r.tax_pct is not none else 0) }}%</td>
      <td class="amt">{{ money(r.this_bill_amount) }}</td>
    </tr>
    {% endfor %}
  </tbody>
  <tfoot>
    <tr>
      <td colspan="10">GROSS THIS BILL (excl. tax)</td>
      <td class="amt">{{ money(doc.gross_this_bill) }}</td>
    </tr>
    {% if (doc.gross_this_bill_with_tax or 0) != (doc.gross_this_bill or 0) %}
    <tr>
      <td colspan="10">GROSS THIS BILL (incl. tax)</td>
      <td class="amt">{{ money(doc.gross_this_bill_with_tax) }}</td>
    </tr>
    {% endif %}
  </tfoot>
</table>

<div class="amount-in-words">
  Gross this bill (incl. tax) in words: {{ frappe.utils.money_in_words(doc.gross_this_bill_with_tax or doc.gross_this_bill or 0, company_currency) }}
</div>
{% else %}
<p>No bill items.</p>
{% endif %}

<div class="doc-footnote">
  End of Annexure 1 &nbsp;·&nbsp; Running Account Bill {{ doc.name }}
</div>

</div>{# /.rab-print #}
